Because webhook endpoints are unauthenticated, we need to verify the request Signature by using the header `X-Shopify-Hmac-Sha256` to verify Shopify is the original sender.
Your secret will be found in your app or private app configuration.
```
const crypto = require("crypto");
// Secret provided by Shopify when creating the webhook
const secret = "YOUR_SECRET";
// Middleware to verify the signature
const verifyShopifyWebhookSignature = (req, res, next) => {
// Retrieve hmac signature from headers
const hmacHeader = req.get("X-Shopify-Hmac-Sha256");
// Calculate hash from body and secret value using sha256
const hash = crypto
.createHmac("sha256", secret)
.update(Buffer.from(req.body))
.digest("base64");
// Fail with 401, Unauthorize
if (hash !== hmacHeader) {
res.sendStatus(401);
} else {
// Proceed
next();
}
};
